.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #3a3d42;
    background: #2f3136;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    background: #40444b;
    border: 1px solid #555;
    border-radius: 8px;
    color: #dcddde;
    padding: 10px 12px;
    font-size: 0.9rem;
    resize: none;
    outline: none;
    font-family: inherit;
    min-height: 20px;
    max-height: 120px;
}

.message-textarea:focus {
    border-color: #7289da;
}

.message-textarea::placeholder {
    color: #72767d;
}

.send-btn {
    background-color: #7289da;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 10px 18px;
    font-size: 0.85rem;
    font-weight: 600;
    cursor: pointer;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background-color: #5b6eae;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

