toolArgs.file_text:
.message-bubble {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-bubble:hover {
    background-color: rgba(255, 255, 255, 0.03);
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 600;
    font-size: 0.92rem;
    color: #fff;
}

.message-time {
    font-size: 0.75rem;
    color: #72767d;
}

.message-content {
    font-size: 0.9rem;
    color: #dcddde;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    background: rgba(114, 137, 218, 0.15);
    border: 1px solid rgba(114, 137, 218, 0.3);
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.82rem;
    cursor: pointer;
    color: #dcddde;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: rgba(114, 137, 218, 0.3);
}

.reaction-count {
    font-size: 0.75rem;
    font-weight: 600;
}

.thread-link {
    background: none;
    border: none;
    color: #7289da;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0;
    margin-top: 4px;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 16px;
    display: flex;
    gap: 2px;
    background: #2a2d32;
    border: 1px solid #444;
    border-radius: 6px;
    padding: 2px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.3);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 0.78rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    white-space: nowrap;
    transition: background-color 0.15s, color 0.15s;
}

.action-btn:hover {
    background: rgba(255, 255, 255, 0.08);
    color: #fff;
}

.react-wrapper {
    position: relative;
}

