arguments.file_text:
@using sv_b31c77cd9367424c931fad476f40c316.Services

<aside class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</aside>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int ActiveChannelId { get; set; }
    [Parameter] public EventCallback<Channel> OnChannelSelected { get; set; }
}

.channel-sidebar {
    width: 260px;
    min-width: 200px;
    background-color: #2f3136;
    display: flex;
    flex-direction: column;
    border-right: 1px solid #222;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid #222;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
    text-transform: uppercase;
    letter-spacing: 0.5px;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.channel-list::-webkit-scrollbar {
    width: 4px;
}

.channel-list::-webkit-scrollbar-thumb {
    background: #555;
    border-radius: 2px;
}

@using sv_b31c77cd9367424c931fad476f40c316.Services

<div class="message-list" @ref="_listRef">
    @if (_loadingMore)
    {
        <div class="load-more-indicator">Loading older messages…</div>
    }
    else if (HasMore)
    {
        <div class="load-more-area">
            <button class="load-more-btn" @onclick="LoadMore">Load older messages</button>
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageBubble Message="message"
                       ReplyCount="GetReplyCount(message.Id)"
                       OnOpenThread="OnOpenThread"
                       OnReact="OnReact" />
    }

    <div @ref="_bottomAnchor"></div>
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private ElementReference _listRef;
    private ElementReference _bottomAnchor;
    private bool _loadingMore;

    private int GetReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    private async Task LoadMore()
    {
        _loadingMore = true;
        await OnLoadMore.InvokeAsync();
        _loadingMore = false;
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.message-list::-webkit-scrollbar {
    width: 6px;
}

.message-list::-webkit-scrollbar-thumb {
    background: #555;
    border-radius: 3px;
}

.load-more-area {
    text-align: center;
    padding: 12px;
}

.load-more-btn {
    background: rgba(114, 137, 218, 0.15);
    border: 1px solid rgba(114, 137, 218, 0.3);
    color: #7289da;
    padding: 6px 16px;
    border-radius: 16px;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.load-more-btn:hover {
    background: rgba(114, 137, 218, 0.3);
}

.load-more-indicator {
    text-align: center;
    padding: 12px;
    color: #72767d;
    font-size: 0.85rem;
}

@using sv_b31c77cd9367424c931fad476f40c316.Services

<aside class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
