toolArgs.file_text:
@using sv_b31c77cd9367424c931fad476f40c316.Services

<aside class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-messages">
            @foreach (var reply in ThreadMessages)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="reply-author">@reply.Author</span>
                        <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnSendReply" />
    }
</aside>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> ThreadMessages { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.thread-panel {
    width: 340px;
    min-width: 280px;
    background-color: #36393f;
    border-left: 1px solid #222;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 16px;
    border-bottom: 1px solid #3a3d42;
}

.thread-header h4 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    color: #fff;
}

.close-btn {
    background: none;
    border: none;
    color: #b9bbbe;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 4px 8px;
    border-radius: 4px;
    transition: background-color 0.15s, color 0.15s;
}

.close-btn:hover {
    background: rgba(255, 255, 255, 0.08);
    color: #fff;
}

.thread-root-message {
    padding: 12px 16px;
    background: rgba(0, 0, 0, 0.15);
    border-bottom: 1px solid #3a3d42;
}

.root-author {
    font-weight: 600;
    font-size: 0.88rem;
    color: #fff;
    margin-bottom: 4px;
}

.root-content {
    font-size: 0.85rem;
    color: #b9bbbe;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

.thread-divider {
    display: flex;
    align-items: center;
    padding: 8px 16px;
    gap: 8px;
}

.thread-divider::before,
.thread-divider::after {
    content: '';
    flex: 1;
    border-top: 1px solid #3a3d42;
}

.thread-divider span {
    font-size: 0.75rem;
    color: #72767d;
    white-space: nowrap;
}

.thread-messages {
    flex: 1;
    overflow-y: auto;
    padding: 4px 0;
}

.thread-messages::-webkit-scrollbar {
    width: 4px;
}

.thread-messages::-webkit-scrollbar-thumb {
    background: #555;
    border-radius: 2px;
}

.thread-reply {
    padding: 8px 16px;
}

.reply-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.reply-author {
    font-weight: 600;
    font-size: 0.85rem;
    color: #fff;
}

.reply-time {
    font-size: 0.72rem;
    color: #72767d;
}

.reply-content {
    font-size: 0.85rem;
    color: #dcddde;
    line-height: 1.4;
    white-space: pre-wrap;
    word-break: break-word;
}

