arguments.file_text:
@page "/chat"
@layout ChatLayout
@using sv_b31c77cd9367424c931fad476f40c316.Services
@using sv_b31c77cd9367424c931fad476f40c316.Components.Chat
@using sv_b31c77cd9367424c931fad476f40c316.Components.Layout
@rendermode InteractiveServer
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<ChannelSidebar Channels="_channels"
                ActiveChannelId="@(_selectedChannel?.Id ?? 0)"
                OnChannelSelected="SelectChannel" />

<div class="message-area @(_threadOpen ? "" : "expanded")">
    @if (_selectedChannel is not null)
    {
        <div class="channel-header">
            <h2># @_selectedChannel.Name</h2>
            <span class="channel-desc">@_selectedChannel.Description</span>
        </div>

        <MessageList Messages="_messages"
                     ThreadSummaries="_threadSummaries"
                     HasMore="_hasMoreMessages"
                     OnLoadMore="LoadOlderMessages"
