+@code {
+    private const int PageSize = 30;
+
+    private List<Channel> _channels = [];
+    private Channel? _selectedChannel;
+    private List<Message> _messages = [];
+    private Dictionary<int, ThreadSummary> _threadSummaries = [];
+    private bool _hasMoreMessages;
+    private bool _loading;
+
+    // Thread state
+    private bool _threadOpen;
+    private Message? _threadRootMessage;
+    private List<Message> _threadMessages = [];
+
+    protected override async Task OnInitializedAsync()
+    {
+        _channels = await ChatService.GetChannelsAsync();
+        if (_channels.Count > 0)
+        {
+            await SelectChannel(_channels[0]);
+        }
+    }
+
+    private async Task SelectChannel(Channel channel)
+    {
+        if (_selectedChannel?.Id == channel.Id) return;
+
+        _selectedChannel = channel;
+        _messages = [];
+        _threadSummaries = [];
+        _hasMoreMessages = false;
+        CloseThreadSync();
+
+        await LoadMessages();
+        await ChatService.MarkChannelReadAsync(channel.Id);
+
+        // Refresh unread count for this channel
+        _channels = await ChatService.GetChannelsAsync();
+    }
+
+    private async Task LoadMessages()
+    {
+        if (_selectedChannel is null) return;
+
+        var loaded = await ChatService.GetMessagesAsync(_selectedChannel.Id, 0, PageSize);
+        _messages = loaded;
+        _hasMoreMessages = loaded.Count >= PageSize;
+        await BuildThreadSummaries();
+    }
+
+    private async Task LoadOlderMessages()
+    {
+        if (_selectedChannel is null || _loading) return;
+        _loading = true;
+
+        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _messages.Count, PageSize);
+        if (older.Count > 0)
+        {
+            _messages.InsertRange(0, older);
+        }
+        _hasMoreMessages = older.Count >= PageSize;
+        _loading = false;
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (_selectedChannel is null) return;
+
+        var message = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
+        _messages.Add(message);
+    }
+
+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+        // Refresh messages to show updated reactions
+        if (_selectedChannel is not null)
+        {
+            _messages = await ChatService.GetMessagesAsync(
+                _selectedChannel.Id, 0, Math.Max(_messages.Count, PageSize));
+        }
+    }
+
+    private async Task OpenThread(int rootMessageId)
+    {
+        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
+        if (_threadRootMessage is null) return;
+
+        _threadMessages = await ChatService.GetThreadAsync(rootMessageId);
+        _threadOpen = true;
+    }
+
+    private void CloseThreadSync()
+    {
+        _threadOpen = false;
+        _threadRootMessage = null;
+        _threadMessages = [];
+    }
+
+    private Task CloseThread()
+    {
+        CloseThreadSync();
+        return Task.CompletedTask;
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (_threadRootMessage is null || _selectedChannel is null) return;
+
+        await ChatService.SendMessageAsync(_selectedChannel.Id, content, _threadRootMessage.Id);
+        _threadMessages = await ChatService.GetThreadAsync(_threadRootMessage.Id);
+        await BuildThreadSummaries();
+    }
+
+    private async Task BuildThreadSummaries()
+    {
+        _threadSummaries = [];
+        // Find messages that are thread roots (have replies)
+        var rootIds = _messages
+            .Where(m => m.ReplyToId is null)
+            .Select(m => m.Id)
+            .ToHashSet();
+
+        foreach (var rootId in rootIds)
+        {
+            try
+            {
+                var thread = await ChatService.GetThreadAsync(rootId);
+                if (thread.Count > 0)
+                {
+                    _threadSummaries[rootId] = new ThreadSummary(
+                        rootId, thread.Count, thread[^1].SentAt);
+                }
+            }
+            catch
+            {
+                // Thread may not exist yet
+            }
+        }
+    }
+}
+

