.message-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    background-color: #36393f;
    overflow: hidden;
    min-width: 0;
}

.message-area.expanded {
    /* Takes full remaining width when thread is closed */
}

.channel-header {
    padding: 12px 16px;
    border-bottom: 1px solid #3a3d42;
    display: flex;
    align-items: baseline;
    gap: 12px;
    flex-shrink: 0;
}

.channel-header h2 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    white-space: nowrap;
}

.channel-desc {
    font-size: 0.85rem;
    color: #72767d;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
}

.empty-state p {
    color: #72767d;
    font-size: 1.1rem;
}

